743:     // Append literal character when possible. Then inclease the buffer_length.
744:     fn append_literal(self: *State, c: u8) void {
745:         // Only allow a-zA-Z.
746:         assert(std.ascii.isAlphabetic(c));
747:         // Could not append if the buffer_length is full.
748:         assert(self.buffer_length < std.math.maxInt(@TypeOf(self.buffer_length)));
749: 
750:         // Check if we can add new span for input character.
751:         if (self.buffer_length < self.buffer_effective.len) {
752:             // Add character to span.
753:             self.buffer_effective[self.buffer_length] = Span.init(c);
754:         }
755:         // Increase the buffer length for tracking, we will need it went handling backspace.
756:         self.buffer_length += 1;
757: 
758:         // After increase, the new buffer_length may exceed the buffer_effective, set literal_index if needed.
759:         if (self.mode == .telex and self.literal_index == null and self.buffer_length == self.buffer_effective.len + 1) {
760:             self.literal_index = self.buffer_length - 1;
761:         }
762:     }
763: 
764:     // Return the last item in buffer_effective, not valid if the buffer_length is out of range.
765:     fn buffer_effective_last(self: *State) Span {
766:         // 1. Should not work if buffer_length exceed buffer_effective.
767:         // 2. Bufeer must have al least 1 character.
768:         assert(self.buffer_length > 0 and self.buffer_length <= self.buffer_effective.len);
769: 
770:         return self.buffer_effective[self.buffer_length - 1];
771:     }
772: 
773:     fn backspace(self: *State) void {
774:         // buffer_length must be positive for backspace.
775:         assert(self.buffer_length > 0);
776: 
777:         // Input mode must be either .literal or .telex.
778:         assert(self.mode == .literal or self.mode == .telex);
779: 
780:         if (self.literal_index) |literal_index| {
781:             // Input mode must be .telex when literal_index is set.
782:             assert(self.mode == .telex);
783:             // literal_index must be within buffer range when set.
784:             assert(literal_index < self.buffer_length);
785:         }
786: 
787:         // decrease the buffer_length to match the backspace.
788:         self.buffer_length -= 1;
789:         // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
790:         self.buffer_modification_index = null;
791:         // if the literal_index is out of buffer range, unset it.
792:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
793:             self.literal_index = null;
794:         }
795:     }
