1952: // Simple ABI wrapper for initialize allocated memory.
1953: export fn lex_state_init(state: *anyopaque) void {
1954:     // Pointer must not be null.
1955:     assert(@intFromPtr(state) != 0);
1956:     // Ensure the allocated memory is aligned.
1957:     assert(@intFromPtr(state) % @alignOf(State) == 0);
1958: 
1959:     const s: *State = @ptrCast(@alignCast(state));
1960:     s.init();
1961: }
1962: 
1963: // Needed for the caller to allocate memory for our State.
1964: export const lex_state_size: usize = @sizeOf(State);
1965: 
1966: // Needed for the caller to allocate memory for our State.
1967: export const lex_state_alignment: usize = @alignOf(State);
1968: 
1969: test "expect State can be initialized by raw allocation" {
1970:     // Arrange
1971: 
1972:     // Allocate memory, only specify on this test to simulate runtime allocation.
1973:     const raw_pointer = std.testing.allocator.rawAlloc(lex_state_size, .fromByteUnits(lex_state_alignment), @returnAddress()) orelse return error.OutOfMemory;
1974:     defer std.testing.allocator.rawFree(raw_pointer[0..lex_state_size], .fromByteUnits(lex_state_alignment), @returnAddress());
1975: 
1976:     // Initialize state.
1977:     lex_state_init(raw_pointer);
1978:     const state: *align(lex_state_alignment) State = @ptrCast(@alignCast(raw_pointer));
1979:     state.mode = .telex;
1980: 
1981:     const input_sequence = "bbbbbqqqqq";
1982: 
